import{_ as s,o as t,c as a,ai as o}from"./chunks/framework.CsYGeNYI.js";const u=JSON.parse('{"title":"认证监控","description":"","frontmatter":{"read_when":["设置认证过期监控或告警","自动化 Claude Code / Codex OAuth 刷新检查"],"summary":"监控模型提供商的 OAuth 过期状态","title":"认证监控","x-i18n":{"generated_at":"2026-02-03T10:03:53Z","model":"claude-opus-4-5","provider":"pi","source_hash":"eef179af9545ed7ab881f3ccbef998869437fb50cdb4088de8da7223b614fa2b","source_path":"automation/auth-monitoring.md","workflow":15}},"headers":[],"relativePath":"zh-CN/automation/auth-monitoring.md","filePath":"zh-CN/automation/auth-monitoring.md","lastUpdated":1771906665000}'),i={name:"zh-CN/automation/auth-monitoring.md"};function d(c,e,l,n,r,h){return t(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="认证监控" tabindex="-1"><a class="header-anchor" href="#认证监控">#</a> 认证监控</h1><p>OpenSoul 通过 <code>opensoul models status</code> 提供 OAuth 过期健康状态。请使用该命令进行自动化和告警；脚本是为手机工作流程提供的可选附加功能。</p><h2 id="推荐方式-cli-检查-可移植" tabindex="-1"><a class="header-anchor" href="#推荐方式-cli-检查-可移植">#</a> 推荐方式：CLI 检查（可移植）</h2><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">opensoul</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> models</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> status</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --check</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>退出码：</p><ul><li><code>0</code>：正常</li><li><code>1</code>：凭证过期或缺失</li><li><code>2</code>：即将过期（24 小时内）</li></ul><p>此方式适用于 cron/systemd，无需额外脚本。</p><h2 id="可选脚本-运维-手机工作流程" tabindex="-1"><a class="header-anchor" href="#可选脚本-运维-手机工作流程">#</a> 可选脚本（运维 / 手机工作流程）</h2><p>这些脚本位于 <code>scripts/</code> 目录下，属于<strong>可选</strong>内容。它们假定你可以通过 SSH 访问 Gateway 网关主机，并针对 systemd + Termux 进行了调优。</p><ul><li><code>scripts/claude-auth-status.sh</code> 现在使用 <code>opensoul models status --json</code> 作为数据来源（如果 CLI 不可用则回退到直接读取文件），因此请确保 <code>opensoul</code> 在定时器的 <code>PATH</code> 中。</li><li><code>scripts/auth-monitor.sh</code>：cron/systemd 定时器目标；发送告警（ntfy 或手机）。</li><li><code>scripts/systemd/opensoul-auth-monitor.{service,timer}</code>：systemd 用户定时器。</li><li><code>scripts/claude-auth-status.sh</code>：Claude Code + OpenSoul 认证检查器（完整/json/简洁模式）。</li><li><code>scripts/mobile-reauth.sh</code>：通过 SSH 引导的重新认证流程。</li><li><code>scripts/termux-quick-auth.sh</code>：一键小部件状态查看 + 打开认证 URL。</li><li><code>scripts/termux-auth-widget.sh</code>：完整的引导式小部件流程。</li><li><code>scripts/termux-sync-widget.sh</code>：同步 Claude Code 凭证 → OpenSoul。</li></ul><p>如果你不需要手机自动化或 systemd 定时器，可以跳过这些脚本。</p>',11)])])}const m=s(i,[["render",d]]);export{u as __pageData,m as default};
